<?php
require_once __DIR__ . '/../includes/bootstrap.php';
$settings = website_settings(); $site = $settings['site'];
$items = array_values(array_filter($settings['navigation'], static fn(array $item): bool => $item['enabled'] && $item['label'] !== '' && $item['url'] !== ''));
$groups = []; foreach ($items as $item) { $groups[$item['group'] ?: 'Explore'][] = $item; }
?>
<div class="container footer-content energy-footer-grid"><div class="footer-intro"><div class="footer-brand"><img src="/images/logo/New dakshayani logo centered small.png" alt="" class="brand-logo-em"><span class="brand-text"><?= htmlspecialchars($site['company_name']) ?></span></div><p><?= htmlspecialchars($site['positioning']) ?></p><p class="footer-promise">Solar lagwana easy hai. Solar ko 25 saal chalwana expertise ka kaam hai.</p><div class="footer-social" aria-label="Social links"><?php foreach ($site['social'] as $network => $url): if ($url === '') continue; ?><a href="<?= htmlspecialchars($url) ?>" target="_blank" rel="noopener"><?= htmlspecialchars(ucfirst($network)) ?></a><?php endforeach; ?></div></div><?php foreach (array_slice($groups, 0, 3, true) as $name => $links): ?><div><h4><?= htmlspecialchars($name) ?></h4><ul class="footer-links"><?php foreach ($links as $item): ?><li><a href="<?= htmlspecialchars($item['url']) ?>"><?= htmlspecialchars($item['label']) ?></a></li><?php endforeach; ?></ul></div><?php endforeach; ?><div><h4>Contact</h4><ul class="footer-links"><li><a href="tel:<?= preg_replace('/[^+0-9]/', '', $site['primary_phone']) ?>"><?= htmlspecialchars($site['primary_phone']) ?></a></li><li><a href="mailto:<?= htmlspecialchars($site['primary_email']) ?>"><?= htmlspecialchars($site['primary_email']) ?></a></li><li><?= htmlspecialchars($site['address']) ?></li><li><a href="/policies.html">Policies</a></li></ul></div></div><div class="footer-bottom"><div class="container"><p>© <span data-current-year></span> <?= htmlspecialchars($site['company_name']) ?>. All rights reserved.</p><p>MSME-registered local enterprise · Claims and eligibility subject to assessment.</p></div></div>
